// Definition of a binary tree node
class TreeNode {
    // Constructor to initialize the node with a value
    constructor(val) {
        this.val = val;
        this.left = null;
        this.right = null;
    }
}

class Solution {
    // function to return all nodes at distance K from target
    distanceK(root, target, k) {
        if (!root) return [];

        // Step 1: Build parent pointers for all nodes
        const parentMap = new Map();
        this.mapParents(root, parentMap);

        // Step 2: BFS from target node to collect all nodes at distance K
        return this.bfsFromTarget(target, parentMap, k);
    }

    // BFS to map each node to its parent
    mapParents(root, parentMap) {
        const queue = [root];


        while (queue.length > 0) {
            const node = queue.shift();

            // If left child exists, record its parent and add it to queue
            if (node.left) {
                parentMap.set(node.left, node);
                queue.push(node.left);
            }
            // If right child exists, record its parent and add it to queue
            if (node.right) {
                parentMap.set(node.right, node);
                queue.push(node.right);
            }
        }
    }

    // BFS traversal from target node to find nodes at distance K
    bfsFromTarget(target, parentMap, k) {
        const queue = [target];
        const visited = new Set();
        visited.add(target);
        let currentLevel = 0;

        // Perform BFS until we reach level K
        while (queue.length > 0) {
            if (currentLevel === k) break;

            const size = queue.length;

            for (let i = 0; i < size; i++) {
                const node = queue.shift();

                // Traverse left child
                if (node.left && !visited.has(node.left)) {
                    visited.add(node.left);
                    queue.push(node.left);
                }

                // Traverse right child
                if (node.right && !visited.has(node.right)) {
                    visited.add(node.right);
                    queue.push(node.right);
                }

                // Traverse parent
                const parent = parentMap.get(node);
                if (parent && !visited.has(parent)) {
                    visited.add(parent);
                    queue.push(parent);
                }
            }
            // Increment level after processing all nodes at current level
            currentLevel++;
        }

        // Return all node values at level K
        return queue.map(node => node.val);
    }
}
